using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr docs = app->documents();
    if (!docs)
        return false;

    // Create a document.
    Ptr doc = docs->add(DocumentTypes::FusionDesignDocumentType);
    if (!doc)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr rootComp = design->rootComponent();
    if (!rootComp)
        return false;

    // Create a new sketch on the yz plane.
    Ptr sketches = rootComp->sketches();
    if (!sketches)
        return false;

    Ptr yzPlane = rootComp->yZConstructionPlane();
    if (!yzPlane)
        return false;

    Ptr yzSketch = sketches->add(yzPlane);
    if (!yzSketch)
        return false;

    // Create an object collection for the points.
    Ptr points = ObjectCollection::create();
    if (!points)
        return false;

    // Define the points the spline with fit through.
    points->add(Point3D::create(-5, 0, 0));
    points->add(Point3D::create(5, 1, 0));
    points->add(Point3D::create(6, 4, 3));
    points->add(Point3D::create(7, 6, 6));
    points->add(Point3D::create(2, 3, 0));
    points->add(Point3D::create(0, 1, 0));

    // Create the spline.
    Ptr sketchCurves = yzSketch->sketchCurves();
    if (!sketchCurves)
        return false;

    Ptr splines = sketchCurves->sketchFittedSplines();
    if (!splines)
        return false;

    Ptr spline = splines->add(points);
    if (!spline)
        return false;

    // Get sketch lines
    Ptr sketchLines = sketchCurves->sketchLines();
    if (!sketchLines)
        return false;

    // Create sketch rectangle
    Ptr startPoint = Point3D::create(0, 0, 0);
    Ptr endPoint = Point3D::create(5.0, 5.0, 0);
    sketchLines->addTwoPointRectangle(startPoint, endPoint);

    // Get two sketch lines
    Ptr sketchLineOne = sketchLines->item(0);
    Ptr sketchLineTwo = sketchLines->item(1);

    // Get the profile
    Ptr profs = yzSketch->profiles();
    if (!profs)
        return false;

    Ptr prof = profs->item(0);

    // Create an extrusion input
    Ptr feats = rootComp->features();
    if (!feats)
        return false;

    Ptr extrudes = feats->extrudeFeatures();
    if (!extrudes)
        return false;

    Ptr extInput = extrudes->createInput(prof, FeatureOperations::NewBodyFeatureOperation);

    // Define that the extent is a distance extent of 5 cm
    Ptr distance = ValueInput::createByReal(5.0);
    // Set the distance extent
    extInput->setDistanceExtent(false, distance);
    // Set the extrude type to be solid
    extInput->isSolid(true);

    // Create the extrusion
    Ptr ext = extrudes->add(extInput);
    if (!ext)
        return false;

    // Get the body with the extrude
    Ptr bodies = ext->bodies();
    if (!bodies)
        return false;

    Ptr body = bodies->item(0);

    // Get a vertex of the body
    Ptr vertices = body->vertices();
    if (!vertices)
        return false;

    Ptr vertex = vertices->item(5);

    // Get a face of the vertex
    Ptr vertexFaces = vertex->faces();
    if (!vertexFaces)
        return false;
    Ptr face = vertexFaces->item(0);

    // Get construction axes
    Ptr constructionAxes = rootComp->constructionAxes();
    if (!constructionAxes)
        return false;

    // Create construction axis input
    Ptr axisInput = constructionAxes->createInput();
    if (!axisInput)
        return false;

    // Create perpendicular construction axis
    axisInput->setByPerpendicularAtPoint(face, vertex);
    Ptr axis = constructionAxes->add(axisInput);

    // Get construction points
    Ptr constructionPoints = rootComp->constructionPoints();
    if (!constructionPoints)
        return false;

    // Create construction point input
    Ptr pointInput = constructionPoints->createInput();
    if (!pointInput)
        return false;

    // Create construction point by two points
    pointInput->setByTwoEdges(sketchLineOne, sketchLineTwo);
    Ptr point = constructionPoints->add(pointInput);

    // Create construction plane
    Ptr planes = rootComp->constructionPlanes();
    if (!planes)
        return false;

    // Create construction plane input
    Ptr planeInput = planes->createInput();
    if (!planeInput)
        return false;

    // Add construction plane by offset
    Ptr offsetValue = ValueInput::createByReal(3.0);
    planeInput->setByOffset(prof, offsetValue);
    Ptr plane = planes->add(planeInput);

    // Create a new sketch on the xz plane.
    Ptr xzPlane = rootComp->xZConstructionPlane();
    if (!xzPlane)
        return false;

    Ptr xzSketch = sketches->add(xzPlane);
    if (!xzSketch)
        return false;

    std::vector> entities;
    entities.push_back(body);
    entities.push_back(face);
    entities.push_back(sketchLineOne);
    entities.push_back(vertex);
    entities.push_back(spline);
    entities.push_back(axis);
    entities.push_back(point);
    entities.push_back(plane);

    std::vector> resVec = xzSketch->intersectWithSketchPlane(entities);
    if (resVec.empty())
        return false;

    return true;
}
